        response = self.es.search(index=index_name, body={
            "size": 0,
            "aggs": {
                "logs_aggregation": {
                    "terms": {
                        "field": aggregation_field,
                        "size": 10
                    }
                }
            }
        })
        return response['aggregations']['logs_aggregation']['buckets']

